// Simplified illustration of how client-side routing works
// (React Router and TanStack Router do this internally)

// 1. Intercept link clicks
document.addEventListener('click', (e) => {
  const link = e.target.closest('a[href]');
  if (!link || link.origin !== location.origin) return;
  e.preventDefault(); // don't reload
  navigate(link.pathname);
});

// 2. Update URL without a reload
function navigate(path) {
  history.pushState(null, '', path); // changes address bar
  renderRoute(path);                  // React re-renders the view
}

// 3. Handle back/forward buttons
window.addEventListener('popstate', () => {
  renderRoute(location.pathname);
});

// Next.js App Router — this component runs on the server by default
// The returned JSX becomes HTML before it reaches the browser
export default async function ProductPage({ params }: { params: { id: string } }) {
  // fetch() runs server-side — no CORS, no loading spinner
  const product = await fetch(`https://api.example.com/products/${params.id}`, {
    next: { revalidate: 60 }, // revalidate cache every 60 seconds
  }).then(r => r.json());

  return (
    <main>
      <h1>{product.name}</h1>
      <p>{product.description}</p>
      {/* Client components (interactive parts) are marked separately */}
      <AddToCartButton productId={product.id} />
    </main>
  );
}

# nginx configuration for a React SPA
server {
  listen 80;
  root /var/www/app;

  location / {
    try_files $uri $uri/ /index.html;  # catch-all: serve index.html
  }

  # Static assets can be cached aggressively
  location ~* \.(js|css|png|jpg|svg)$ {
    expires 1y;
    add_header Cache-Control "public, immutable";
  }
}

import { lazy, Suspense } from 'react';
import { Route, Routes } from 'react-router-dom';

// Each route's bundle is fetched only when the route is first visited
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Settings = lazy(() => import('./pages/Settings'));
const Reports = lazy(() => import('./pages/Reports'));

function App() {
  return (
    <Suspense fallback={<PageSpinner />}>
      <Routes>
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/settings" element={<Settings />} />
        <Route path="/reports" element={<Reports />} />
      </Routes>
    </Suspense>
  );
}

// In a Next.js app, the root HTML is produced on the server.
// On the client, hydrateRoot (React 18) attaches to the existing DOM:
import { hydrateRoot } from 'react-dom/client';
import App from './App';

// In a pure SPA (Vite), createRoot is used instead — no pre-existing HTML:
import { createRoot } from 'react-dom/client';
createRoot(document.getElementById('root')!).render(<App />);

// hydrateRoot expects matching HTML from the server;
// a mismatch causes a hydration error and React falls back to
// re-rendering the entire tree client-side (slower, warns in dev)

// TanStack Router prefetches on hover by default
import { Link } from '@tanstack/react-router';

function Nav() {
  return (
    <nav>
      {/* Hovering prefetches the Dashboard bundle */}
      <Link to="/dashboard" preload="intent">Dashboard</Link>
      <Link to="/settings" preload="intent">Settings</Link>
    </nav>
  );
}

// Protected route pattern with React Router v6
import { Navigate, Outlet } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

function ProtectedRoute() {
  const { user, isLoading } = useAuth();

  if (isLoading) return <PageSpinner />;
  if (!user) return <Navigate to="/login" replace />;
  return <Outlet />; // renders the nested protected route
}

// In the router:
<Routes>
  <Route path="/login" element={<LoginPage />} />
  <Route element={<ProtectedRoute />}>
    <Route path="/dashboard" element={<Dashboard />} />
    <Route path="/settings" element={<Settings />} />
  </Route>
</Routes>

useEffect(() => {
  const controller = new AbortController();

  fetch('/api/data', { signal: controller.signal })
    .then(r => r.json())
    .then(data => setData(data))
    .catch(err => {
      if (err.name === 'AbortError') return; // unmounted — ignore
      setError(err.message);
    });

  return () => controller.abort(); // cancel on unmount
}, []);

// React Router v6 — block navigation when form is dirty
import { useBlocker } from 'react-router-dom';

function EditForm({ isDirty }: { isDirty: boolean }) {
  useBlocker(
    ({ currentLocation, nextLocation }) =>
      isDirty && currentLocation.pathname !== nextLocation.pathname
  );
  // When blocked, React Router will NOT navigate and you must show a confirmation dialog
}
